// Imposta lo zoom/scala iniziale
vec2 z_pos = (uv - 0.5) * 3.0; 

// Costante complessa C
vec2 c = vec2(0.285, 0.01); 

int maxIter = 80; // Ridotto leggermente per sicurezza
int i = 0;

// Iterazione Julia standard
for(i = 0; i < maxIter; i++) {
    // Usiamo nomi sicuri (zx, zy) invece di x, y
    float zx = (z_pos.x * z_pos.x - z_pos.y * z_pos.y) + c.x;
    float zy = (2.0 * z_pos.x * z_pos.y) + c.y;
    z_pos = vec2(zx, zy);

    if (dot(z_pos, z_pos) > 4.0) break;
}

// Colorazione
if (i == maxIter) {
    return vec3(0.2, 0.15, 0.3); 
} else {
    float t = float(i) / 20.0;

    float r = 0.5 + 0.5 * sin(t + 0.0);
    float g = 0.5 + 0.5 * cos(t + 2.09); 
    float b = 0.5 + 0.5 * cos(t + 4.18); 

    vec3 color = vec3(r, g, b);

    // Mix esplicito
    return mix(color, vec3(1.0, 1.0, 1.0), 0.5);
}
